/**
 * Role statistics from 2,146 parsed Avalon games (2020-2023).
 * Source: content/_data/roles/ JSON files generated by parse_roles.py (M0.3).
 * Canonical 7 roles only.
 */

export interface SeatWinRates {
  [seat: string]: number;
}

export interface ResultBreakdown {
  /** Evil wins 3 quests */
  '\u4e09\u7d05': number;
  /** Good wins 3 quests but Merlin assassinated */
  '\u4e09\u85cd\u6b7b': number;
  /** Good wins 3 quests and Merlin survives */
  '\u4e09\u85cd\u6d3b': number;
}

export interface RoleStats {
  total_games: number;
  wins: number;
  losses: number;
  win_rate: number;
  aggregate_win_rate: number;
  result_breakdown: ResultBreakdown;
  seat_distribution: Record<string, number>;
  seat_win_rates: SeatWinRates;
}

export interface RoleData {
  id: string;
  slug: string;
  name_zh: string;
  name_en: string;
  faction: 'good' | 'evil';
  abbrev: string;
  ability: string;
  stats: RoleStats;
}

