/** Map wiki article IDs to role stat keys */
export const ARTICLE_TO_ROLE: Record<string, string> = {
  'roles-merlin': 'merlin',
  'roles-percival': 'percival',
  'roles-loyal': 'loyal_servant',
  'roles-assassin': 'assassin',
  'roles-morgana': 'morgana',
  'roles-mordred': 'mordred',
  'roles-oberon': 'oberon',
};

/** Get all roles sorted: good first, then evil */
export function getAllRoles(): RoleData[] {
  const good = ['merlin', 'percival', 'loyal_servant'];
  const evil = ['mordred', 'morgana', 'assassin', 'oberon'];
  return [...good, ...evil].map((k) => ROLE_STATS[k]);
}

/** Format win rate as percentage string */
export function formatWinRate(rate: number): string {
  return `${(rate * 100).toFixed(1)}%`;
}

/** Total games across all roles (unique games, not role-appearances) */
export const TOTAL_UNIQUE_GAMES = 2146;
